import {
  buildRunnerUsedNormalizedPayload,
  buildRunnerUsedPayload,
  inferRunnerHostedType,
} from '../src/runner-metadata';

describe('runner-metadata', () => {
  it('infers github hosted runner', () => {
    const inferred = inferRunnerHostedType({ runnerName: 'GitHub Actions 2', labels: ['ubuntu-latest'] });
    expect(inferred.hostedType).toBe('github_hosted');
    expect(inferred.ephemeral).toBe(true);
    expect(inferred.selfHosted).toBe(false);
  });

  it('infers self-hosted runner', () => {
    const inferred = inferRunnerHostedType({ runnerName: 'my-runner', labels: ['self-hosted', 'linux'] });
    expect(inferred.hostedType).toBe('self_hosted');
    expect(inferred.selfHosted).toBe(true);
  });

  it('handles unknown labels without crashing', () => {
    const payload = buildRunnerUsedPayload({ labels: undefined, runnerName: 'custom-agent' });
    expect(payload.labels).toEqual([]);
    expect(payload.hostedType).toBe('unknown');
  });

  it('builds runner.used payload without secrets', () => {
    const payload = buildRunnerUsedPayload({
      runnerName: 'GitHub Actions 2',
      runnerOs: 'Linux',
      runnerArch: 'X64',
      labels: ['ubuntu-latest'],
      workflowJobId: '12345',
    });
    expect(payload.hostedType).toBe('github_hosted');
    expect(JSON.stringify(payload)).not.toMatch(/ghs_|ghp_|Bearer /);
  });

  it('includes workflowJobId in normalized payload when provided', () => {
    const runner = buildRunnerUsedPayload({ runnerName: 'GitHub Actions 2', labels: ['ubuntu-latest'] });
    const normalized = buildRunnerUsedNormalizedPayload({
      organizationId: 'org_1',
      repository: 'org/repo',
      workflowRunId: '999',
      workflowJobId: '12345',
      runner,
    });
    expect(normalized['workflowJobId']).toBe('12345');
    expect(normalized['signalType']).toBe('runner.used');
    expect(normalized['source']).toBe('github_actions');
  });
});
